/** @jsxImportSource react */
import { TextStyleContext } from './text';
import { useRegistryTheme } from '../../lib/theme';
import * as React from 'react';
import {
    Pressable,
    StyleSheet,
    View,
    type PressableProps,
    type PressableStateCallbackType,
    type StyleProp,
    type TextStyle,
    type ViewStyle,
} from 'react-native';

type ButtonVariant = 'default' | 'destructive' | 'outline' | 'secondary' | 'ghost' | 'link';
type ButtonSize = 'default' | 'sm' | 'lg' | 'icon';

type ButtonProps = Omit<PressableProps, 'children'> & {
    children?: React.ReactNode;
    className?: string;
    variant?: ButtonVariant;
    size?: ButtonSize;
};

function getButtonStyle(variant: ButtonVariant, theme: ReturnType<typeof useRegistryTheme>): StyleProp<ViewStyle> {
    switch (variant) {
        case 'destructive':
            return {
                backgroundColor: 'rgba(239, 68, 68, 0.12)',
                borderColor: 'transparent',
                borderWidth: 1,
            };
        case 'outline':
            return {
                backgroundColor: theme.background,
                borderColor: theme.border,
                borderWidth: 1,
            };
        case 'secondary':
            return {
                backgroundColor: theme.secondary,
                borderColor: 'transparent',
                borderWidth: 1,
            };
        case 'ghost':
            return {
                backgroundColor: 'transparent',
                borderColor: 'transparent',
                borderWidth: 1,
            };
        case 'link':
            return {
                backgroundColor: 'transparent',
                borderColor: 'transparent',
                borderWidth: 0,
                paddingHorizontal: 0,
                paddingVertical: 0,
                minHeight: undefined,
            };
        default:
            return {
                backgroundColor: theme.primary,
                borderColor: 'transparent',
                borderWidth: 1,
            };
    }
}

function getButtonTextStyle(variant: ButtonVariant, theme: ReturnType<typeof useRegistryTheme>): TextStyle {
    switch (variant) {
        case 'destructive':
            return { color: '#dc2626' };
        case 'outline':
            return { color: theme.foreground };
        case 'secondary':
            return { color: theme.secondaryForeground };
        case 'ghost':
            return { color: theme.foreground };
        case 'link':
            return { color: theme.primary, textDecorationLine: 'underline' };
        default:
            return { color: theme.primaryForeground };
    }
}

function getSizeStyle(size: ButtonSize): StyleProp<ViewStyle> {
    switch (size) {
        case 'sm':
            return styles.smButton;
        case 'lg':
            return styles.lgButton;
        case 'icon':
            return styles.iconButton;
        default:
            return styles.mdButton;
    }
}

function Button({ style, variant = 'default', size = 'default', disabled, children, ...props }: ButtonProps) {
    const theme = useRegistryTheme();

    return (
        <Pressable
            disabled={disabled}
            role="button"
            style={(state: PressableStateCallbackType) => {
                const resolvedStyle =
                    typeof style === 'function'
                        ? style(state)
                        : (style as StyleProp<ViewStyle>);

                return [
                    styles.pressable,
                    resolvedStyle,
                ];
            }}
            {...props}
        >
            {({ pressed }) => (
                <TextStyleContext.Provider value={[styles.buttonTextBase, getButtonTextStyle(variant, theme)]}>
                    <View
                        style={[
                            styles.baseButton,
                            getButtonStyle(variant, theme),
                            getSizeStyle(size),
                            pressed && variant !== 'link'
                                ? variant === 'ghost'
                                    ? styles.ghostPressed
                                    : styles.pressed
                                : undefined,
                            disabled ? styles.disabled : undefined,
                        ]}
                    >
                        {children}
                    </View>
                </TextStyleContext.Provider>
            )}
        </Pressable>
    );
}

const styles = StyleSheet.create({
    pressable: {
        alignSelf: 'flex-start',
    },
    baseButton: {
        alignItems: 'center',
        borderRadius: 8,
        flexDirection: 'row',
        justifyContent: 'center',
        shadowColor: '#000',
        shadowOffset: { width: 0, height: 1 },
        shadowOpacity: 0,
        shadowRadius: 0,
    },
    mdButton: {
        gap: 6,
        minHeight: 32,
        paddingHorizontal: 10,
        paddingVertical: 6,
    },
    smButton: {
        gap: 4,
        minHeight: 28,
        paddingHorizontal: 10,
        paddingVertical: 4,
    },
    lgButton: {
        gap: 6,
        minHeight: 36,
        paddingHorizontal: 12,
        paddingVertical: 8,
    },
    iconButton: {
        height: 32,
        justifyContent: 'center',
        paddingHorizontal: 0,
        width: 32,
    },
    pressed: {
        opacity: 0.96,
        transform: [{ translateY: 1 }],
    },
    ghostPressed: {
        backgroundColor: 'rgba(0,0,0,0.04)',
    },
    disabled: {
        opacity: 0.5,
    },
    buttonTextBase: {
        fontSize: 14,
        fontWeight: '500',
        lineHeight: 18,
    },
});

export { Button };
export type { ButtonProps };

/** @jsxImportSource react */
import * as Slot from '@rn-primitives/slot';
import { useRegistryTheme } from '../../lib/theme';
import * as React from 'react';
import {
    Platform,
    StyleSheet,
    Text as RNText,
    type Role,
    type StyleProp,
    type TextStyle,
} from 'react-native';

type TextVariant =
    | 'default'
    | 'h1'
    | 'h2'
    | 'h3'
    | 'h4'
    | 'p'
    | 'blockquote'
    | 'code'
    | 'lead'
    | 'large'
    | 'small'
    | 'muted';

type TextProps = React.ComponentProps<typeof RNText> &
    React.RefAttributes<RNText> & {
        asChild?: boolean;
        className?: string;
        variant?: TextVariant;
    };

const ROLE: Partial<Record<TextVariant, Role>> = {
    h1: 'heading',
    h2: 'heading',
    h3: 'heading',
    h4: 'heading',
    blockquote: Platform.select({ web: 'blockquote' as Role }),
    code: Platform.select({ web: 'code' as Role }),
};

const ARIA_LEVEL: Partial<Record<TextVariant, string>> = {
    h1: '1',
    h2: '2',
    h3: '3',
    h4: '4',
};

const TextStyleContext = React.createContext<StyleProp<TextStyle> | undefined>(undefined);

const styles = StyleSheet.create({
    base: {
        fontSize: 16,
        letterSpacing: -0.1,
    },
    defaultTextStyles: {},
    h1: {
        fontSize: 36,
        fontWeight: '800',
        letterSpacing: -0.8,
        lineHeight: 40,
    },
    h2: {
        fontSize: 30,
        fontWeight: '600',
        letterSpacing: -0.6,
        lineHeight: 34,
        paddingBottom: 8,
        borderBottomWidth: StyleSheet.hairlineWidth,
    },
    h3: {
        fontSize: 24,
        fontWeight: '600',
        letterSpacing: -0.4,
        lineHeight: 28,
    },
    h4: {
        fontSize: 20,
        fontWeight: '600',
        letterSpacing: -0.2,
        lineHeight: 24,
    },
    p: {
        lineHeight: 24,
    },
    blockquote: {
        borderLeftWidth: 3,
        fontStyle: 'italic',
        paddingLeft: 12,
    },
    code: {
        borderRadius: 6,
        fontFamily: Platform.select({ ios: 'Menlo', android: 'monospace', default: 'monospace' }),
        fontSize: 13,
        fontWeight: '600',
        overflow: 'hidden',
        paddingHorizontal: 6,
        paddingVertical: 4,
    },
    lead: {
        fontSize: 20,
        lineHeight: 28,
    },
    large: {
        fontSize: 18,
        fontWeight: '600',
        lineHeight: 24,
    },
    small: {
        fontSize: 14,
        fontWeight: '500',
        lineHeight: 14,
    },
    muted: {
        fontSize: 14,
        lineHeight: 20,
    },
});

function getVariantStyle(variant: TextVariant): StyleProp<TextStyle> {
    switch (variant) {
        case 'h1':
            return styles.h1;
        case 'h2':
            return styles.h2;
        case 'h3':
            return styles.h3;
        case 'h4':
            return styles.h4;
        case 'p':
            return styles.p;
        case 'blockquote':
            return styles.blockquote;
        case 'code':
            return styles.code;
        case 'lead':
            return styles.lead;
        case 'large':
            return styles.large;
        case 'small':
            return styles.small;
        case 'muted':
            return styles.muted;
        default:
            return styles.defaultTextStyles;
    }
}

function Text({ style, asChild = false, variant = 'default', ...props }: TextProps) {
    const inheritedStyle = React.useContext(TextStyleContext);
    const theme = useRegistryTheme();
    const Component = asChild ? Slot.Text : RNText;

    return (
        <Component
            style={[
                styles.base,
                { color: theme.foreground },
                getVariantStyle(variant),
                variant === 'h2' ? { borderBottomColor: theme.border } : undefined,
                variant === 'blockquote' ? { borderLeftColor: theme.border } : undefined,
                variant === 'code' ? { backgroundColor: theme.muted } : undefined,
                variant === 'lead' || variant === 'muted' ? { color: theme.mutedForeground } : undefined,
                inheritedStyle,
                style,
            ]}
            role={ROLE[variant]}
            aria-level={ARIA_LEVEL[variant]}
            {...props}
        />
    );
}

export { Text, TextStyleContext };

import * as React from "react";
import { TextInput, View, type TextInputProps } from "react-native";
import { cn } from "@/lib/utils";

type InputProps = TextInputProps & {
  className?: string;
  containerClassName?: string;
  leftSlot?: React.ReactNode;
  rightSlot?: React.ReactNode;
  size?: "md" | "sm" | "lg";
  variant?: "default" | "ghost";
  invalid?: boolean;
};

const sizeStyles = {
  sm: "h-9 px-2 text-sm",
  md: "h-10 px-3 text-base",
  lg: "h-11 px-4 text-base",
};

export const Input = React.forwardRef<TextInput, InputProps>(
  (
    {
      className,
      containerClassName,
      leftSlot,
      rightSlot,
      size = "md",
      variant = "default",
      editable = true,
      invalid = false,
      onFocus,
      onBlur,
      ...props
    },
    ref,
  ) => {
    const [focused, setFocused] = React.useState(false);

    return (
      <View className={cn("w-full", containerClassName)}>
        <View
          className={cn(
            // base
            "flex-row items-center rounded-lg border transition-colors",

            // size
            sizeStyles[size],

            // variants
            variant === "ghost"
              ? "bg-muted border-transparent"
              : "bg-background border-input",

            // states
            focused && "border-ring ring-2 ring-ring/50",
            invalid && "border-destructive ring-2 ring-destructive/20",

            // disabled
            !editable && "opacity-50",
          )}
        >
          {leftSlot && (
            <View className="pl-2 pr-1 justify-center items-center">
              {leftSlot}
            </View>
          )}

          <TextInput
            ref={ref}
            editable={editable}
            onFocus={(e) => {
              setFocused(true);
              onFocus?.(e);
            }}
            onBlur={(e) => {
              setFocused(false);
              onBlur?.(e);
            }}
            placeholderTextColor="#9ca3af"
            className={cn(
              "flex-1 text-foreground",
              "placeholder:text-muted-foreground",
              className,
            )}
            {...props}
          />

          {rightSlot && (
            <View className="pl-1 pr-2 justify-center items-center">
              {rightSlot}
            </View>
          )}
        </View>
      </View>
    );
  },
);

Input.displayName = "Input";

/** @jsxImportSource react */
import { TextStyleContext } from './text';
import { useRegistryTheme } from '../../lib/theme';
import * as React from 'react';
import { StyleSheet, View, type TextStyle, type ViewProps, type ViewStyle } from 'react-native';

type BadgeVariant = 'default' | 'secondary' | 'destructive' | 'outline';

type BadgeProps = ViewProps & {
    className?: string;
    variant?: BadgeVariant;
};

const styles = StyleSheet.create({
    base: {
        alignItems: 'center',
        borderRadius: 999,
        borderWidth: 1,
        flexDirection: 'row',
        paddingHorizontal: 10,
        paddingVertical: 4,
    },
    textBase: {
        fontSize: 12,
        fontWeight: '600',
        lineHeight: 14,
    },
});

function getContainerStyle(variant: BadgeVariant, theme: ReturnType<typeof useRegistryTheme>): ViewStyle {
    switch (variant) {
        case 'secondary':
            return {
                backgroundColor: theme.secondary,
                borderColor: 'transparent',
            };
        case 'destructive':
            return {
                backgroundColor: 'rgba(239, 68, 68, 0.12)',
                borderColor: 'transparent',
            };
        case 'outline':
            return {
                backgroundColor: theme.background,
                borderColor: theme.border,
            };
        default:
            return {
                backgroundColor: theme.primary,
                borderColor: 'transparent',
            };
    }
}

function getTextStyle(variant: BadgeVariant, theme: ReturnType<typeof useRegistryTheme>): TextStyle {
    switch (variant) {
        case 'secondary':
            return { color: theme.secondaryForeground };
        case 'destructive':
            return { color: '#dc2626' };
        case 'outline':
            return { color: theme.foreground };
        default:
            return { color: theme.primaryForeground };
    }
}

function Badge({ style, variant = 'default', children, ...props }: BadgeProps) {
    const theme = useRegistryTheme();

    return (
        <TextStyleContext.Provider value={[styles.textBase, getTextStyle(variant, theme)]}>
            <View style={[styles.base, getContainerStyle(variant, theme), style]} {...props}>
                {children}
            </View>
        </TextStyleContext.Provider>
    );
}

export { Badge };
export type { BadgeProps };

/** @jsxImportSource react */
import * as React from 'react';
import { Image, StyleSheet, View, type ImageProps, type TextStyle, type ViewProps } from 'react-native';
import { useRegistryTheme } from '../../lib/theme';
import { TextStyleContext } from './text';

type AvatarProps = ViewProps & {
    alt?: string;
    className?: string;
    size?: 'default' | 'sm' | 'lg';
};

type AvatarImageProps = ImageProps & {
    className?: string;
    src?: string;
};

type AvatarFallbackProps = ViewProps & {
    className?: string;
};

const styles = StyleSheet.create({
    base: {
        borderRadius: 999,
        height: 40,
        overflow: 'hidden',
        width: 40,
    },
    image: {
        height: '100%',
        width: '100%',
    },
    fallback: {
        alignItems: 'center',
        flex: 1,
        justifyContent: 'center',
    },
    sizeSm: {
        height: 32,
        width: 32,
    },
    sizeLg: {
        height: 56,
        width: 56,
    },
    sizeXl: {
        height: 80,
        width: 80,
    },
});

function getSizeStyle(className?: string, size: AvatarProps['size'] = 'default') {
    if (size === 'sm') return styles.sizeSm;
    if (size === 'lg') return styles.sizeLg;
    if (!className) return undefined;
    if (className.includes('h-20') || className.includes('w-20') || className.includes('size-20')) return styles.sizeXl;
    if (className.includes('h-16') || className.includes('w-16') || className.includes('size-16')) return styles.sizeLg;
    if (className.includes('h-10') || className.includes('w-10') || className.includes('size-10')) return styles.base;
    if (className.includes('h-8') || className.includes('w-8') || className.includes('size-8')) return styles.sizeSm;
    return undefined;
}

function Avatar({ className, size = 'default', style, ...props }: AvatarProps) {
    return <View style={[styles.base, getSizeStyle(className, size), style]} {...props} />;
}

function AvatarImage({ style, src, source, ...props }: AvatarImageProps) {
    return <Image style={[styles.image, style]} source={source ?? (src ? { uri: src } : undefined)} {...props} />;
}

function AvatarFallback({ style, ...props }: AvatarFallbackProps) {
    const theme = useRegistryTheme();
    const textStyle = React.useMemo<TextStyle>(() => ({
        color: theme.mutedForeground,
        fontSize: 14,
        fontWeight: '500',
    }), [theme.mutedForeground]);

    return (
        <TextStyleContext.Provider value={textStyle}>
            <View style={[styles.fallback, { backgroundColor: theme.muted }, style]} {...props} />
        </TextStyleContext.Provider>
    );
}

export { Avatar, AvatarFallback, AvatarImage };
export type { AvatarFallbackProps, AvatarImageProps, AvatarProps };

import * as React from 'react';
import { Pressable, StyleSheet, View, type PressableProps, type TextProps, type ViewProps } from 'react-native';

import { Text } from './text';
import { useRegistryTheme } from '../../lib/theme';

function Breadcrumb(props: ViewProps) {
    return <View accessibilityRole="summary" {...props} />;
}

function BreadcrumbList({ style, ...props }: ViewProps) {
    return <View style={[styles.list, style]} {...props} />;
}

function BreadcrumbItem({ style, ...props }: ViewProps) {
    return <View style={[styles.item, style]} {...props} />;
}

function BreadcrumbLink({ children, style, ...props }: PressableProps & { children?: React.ReactNode }) {
    const theme = useRegistryTheme();
    return (
        <Pressable {...props}>
            <Text style={[styles.link, { color: theme.mutedForeground }, style as TextProps['style']]}>
                {children}
            </Text>
        </Pressable>
    );
}

function BreadcrumbPage({ children, style, ...props }: TextProps) {
    return (
        <Text accessibilityRole="text" style={[styles.page, style]} {...props}>
            {children}
        </Text>
    );
}

function BreadcrumbSeparator({ children, style, ...props }: TextProps) {
    const theme = useRegistryTheme();
    return (
        <Text
            accessibilityElementsHidden
            importantForAccessibility="no"
            style={[styles.separator, { color: theme.mutedForeground }, style]}
            {...props}
        >
            {children ?? '›'}
        </Text>
    );
}

function BreadcrumbEllipsis(props: TextProps) {
    return <BreadcrumbSeparator {...props}>…</BreadcrumbSeparator>;
}

const styles = StyleSheet.create({
    list: {
        flexDirection: 'row',
        flexWrap: 'wrap',
        alignItems: 'center',
        gap: 6,
    },
    item: {
        flexDirection: 'row',
        alignItems: 'center',
        gap: 6,
    },
    link: {
        fontSize: 14,
        lineHeight: 18,
    },
    page: {
        fontSize: 14,
        fontWeight: '500',
        lineHeight: 18,
    },
    separator: {
        fontSize: 14,
        lineHeight: 18,
    },
});

export {
    Breadcrumb,
    BreadcrumbEllipsis,
    BreadcrumbItem,
    BreadcrumbLink,
    BreadcrumbList,
    BreadcrumbPage,
    BreadcrumbSeparator,
};

/** @jsxImportSource react */
import * as React from 'react';
import { View, StyleSheet, type PressableProps, type ViewProps, type StyleProp, type ViewStyle } from "react-native";

import { Collapsible, CollapsibleContent, CollapsibleTrigger } from './collapsible';
import { Text } from './text';
import { useRegistryTheme } from '../../lib/theme';
import { TextStyleContext } from './text';
import { ChevronDown } from 'lucide-react-native';

type AccordionContextValue = {
    type: 'single' | 'multiple';
    value: string | string[] | undefined;
    onItemToggle: (value: string) => void;
};

type AccordionItemContextValue = {
    value: string;
    open: boolean;
};

type AccordionProps = ViewProps & {
    children?: React.ReactNode;
    type?: 'single' | 'multiple';
    value?: string | string[];
    defaultValue?: string | string[];
    onValueChange?: (value: string | string[]) => void;
};

type AccordionItemProps = ViewProps & {
    children?: React.ReactNode;
    value: string;
};

type AccordionTriggerProps = PressableProps & {
    asChild?: boolean;
    children?: React.ReactNode;
};

type AccordionContentProps = ViewProps & {
    children?: React.ReactNode;
};

const AccordionContext = React.createContext<AccordionContextValue | null>(null);
const AccordionItemContext = React.createContext<AccordionItemContextValue | null>(null);

function useAccordionContext() {
    const context = React.useContext(AccordionContext);

    if (!context) {
        throw new Error('Accordion components must be used inside Accordion.');
    }

    return context;
}

function useAccordionItemContext() {
    const context = React.useContext(AccordionItemContext);

    if (!context) {
        throw new Error('Accordion item components must be used inside AccordionItem.');
    }

    return context;
}

function Accordion({
    children,
    type = 'single',
    value,
    defaultValue,
    onValueChange,
    ...props
}: AccordionProps) {
    const [internalValue, setInternalValue] = React.useState<string | string[] | undefined>(
        defaultValue,
    );
    const isControlled = value !== undefined;
    const resolvedValue = isControlled ? value : internalValue;

    const onItemToggle = React.useCallback(
        (item: string) => {
            let nextValue: string | string[];

            if (type === 'single') {
                nextValue = resolvedValue === item ? '' : item;
            } else {
                const current = Array.isArray(resolvedValue) ? resolvedValue : [];
                nextValue = current.includes(item)
                    ? current.filter((entry) => entry !== item)
                    : [...current, item];
            }

            if (!isControlled) {
                setInternalValue(nextValue);
            }

            onValueChange?.(nextValue);
        },
        [isControlled, onValueChange, resolvedValue, type],
    );

    return (
        <AccordionContext.Provider value={{ type, value: resolvedValue, onItemToggle }}>
            <View {...props}>{children}</View>
        </AccordionContext.Provider>
    );
}

function AccordionItem({ children, value, style, ...props }: AccordionItemProps) {
    const context = useAccordionContext();
    const theme = useRegistryTheme();
    const open = Array.isArray(context.value)
        ? context.value.includes(value)
        : context.value === value;

    return (
        <AccordionItemContext.Provider value={{ value, open }}>
            <Collapsible 
                open={open} 
                onOpenChange={() => context.onItemToggle(value)} 
                style={[styles.item, { borderBottomColor: theme.border }, style]} 
                {...props}
            >
                {children}
            </Collapsible>
        </AccordionItemContext.Provider>
    );
}

function AccordionTrigger({ style, children, asChild = false, ...props }: AccordionTriggerProps) {
    const context = useAccordionItemContext();
    const theme = useRegistryTheme();
    const content =
        typeof children === 'string' || typeof children === 'number' ? (
            <Text>{children}</Text>
        ) : (
            children
        );

    return (
        <CollapsibleTrigger
            asChild={asChild}
            style={(state) => {
                const resolvedStyle = typeof style === "function" ? style(state) : style;
                return asChild ? (resolvedStyle as StyleProp<ViewStyle>) : [
                    state.pressed && styles.triggerPressed,
                    resolvedStyle as StyleProp<ViewStyle>,
                ];
            }}
            {...props}
        >
            {asChild ? (
                children
            ) : (
                <View style={styles.triggerInner}>
                    <TextStyleContext.Provider
                        value={{
                            fontSize: 16,
                            fontWeight: "500",
                            color: theme.foreground,
                        }}
                    >
                        {content}
                    </TextStyleContext.Provider>
                    <ChevronDown
                        size={18}
                        color={theme.mutedForeground}
                        style={{
                            transform: [{ rotate: context.open ? "180deg" : "0deg" }],
                        }}
                    />
                </View>
            )}
        </CollapsibleTrigger>
    );
}

function AccordionContent({ style, children, ...props }: AccordionContentProps) {
    useAccordionItemContext();
    return (
        <CollapsibleContent style={[styles.content, style]} {...props}>
            {children}
        </CollapsibleContent>
    );
}

const styles = StyleSheet.create({
    item: {
        borderBottomWidth: StyleSheet.hairlineWidth,
    },
    triggerInner: {
        flexDirection: "row",
        alignItems: "center",
        justifyContent: "space-between",
        paddingVertical: 16,
        width: "100%",
    },
    triggerPressed: {
        opacity: 0.8,
    },
    content: {
        paddingBottom: 16,
    },
});

export { Accordion, AccordionContent, AccordionItem, AccordionTrigger };
export type {
    AccordionContentProps,
    AccordionItemProps,
    AccordionProps,
    AccordionTriggerProps,
};

import {
    Dialog,
    DialogClose,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from './dialog';

const AlertDialog = Dialog;
const AlertDialogTrigger = DialogTrigger;
const AlertDialogContent = DialogContent;
const AlertDialogHeader = DialogHeader;
const AlertDialogFooter = DialogFooter;
const AlertDialogTitle = DialogTitle;
const AlertDialogDescription = DialogDescription;
