    return (
        <View style={[styles.track, { backgroundColor: theme.secondary }, style]} {...props}>
            <Animated.View
                style={[
                    styles.fill,
                    { backgroundColor: theme.primary },
                    animatedStyle,
                ]}
            />
        </View>
    );
}

